schema_crawl_eeat_json, schema_crawl_eeat_csv, schema_crawl_eeat_live_json = _make_views('schema-crawl-eeat')
analytics_webmaster_readiness_json, analytics_webmaster_readiness_csv, analytics_webmaster_readiness_live_json = _make_views('analytics-webmaster-readiness')

