def _launch_content_completeness_rows():
    counts = _current_counts()
    checks = [
        ('editorial_foundation', 'Editorial foundation seeded', counts['methodologies'] >= 1 and counts['editorial_policies'] >= 5 and counts['authors'] >= 1 and counts['editors'] >= 1 and counts['reviewers'] >= 1, f"methodologies={counts['methodologies']}; policies={counts['editorial_policies']}; authors={counts['authors']}; editors={counts['editors']}; reviewers={counts['reviewers']}", 'methodology, policies, author/editor/reviewer required'),
        ('launch_ready_guides', 'At least 4 launch-ready P0 guides', counts['launch_ready_guides'] >= 4, counts['launch_ready_guides'], 'seed 4 P0 guides with sources, checklist, risk, FAQ and money links'),
        ('indexable_companies', 'At least 50 indexable companies', counts['indexable_companies'] >= 50, counts['indexable_companies'], 'seed 50 filled company dossiers with trust data'),
        ('astana_depth', 'Astana launch depth', City.objects.filter(slug='astana').exists() and Company.objects.filter(service_links__city__slug='astana', index_status='indexable').distinct().count() >= 1, Company.objects.filter(service_links__city__slug='astana', index_status='indexable').distinct().count(), 'Astana city/service routes need company depth'),
        ('keyword_import', 'Stage 4A keyword import present', counts['keywords'] >= 24800 and counts['keyword_evidence'] >= 9246, f"keywords={counts['keywords']}; evidence={counts['keyword_evidence']}", 'import Stage 4A keyword/evidence handoff'),
    ]
    rows = []
    for key, label, passed, actual, note in checks:
        rows.append({'check_key': key, 'label': label, 'status': 'pass' if passed else 'fail', 'actual': actual, 'required': note})
    return rows


