def _robots_from_notes(notes):
    marker = 'actual_robots='
    if marker not in notes:
        return ''
    return notes.split(marker, 1)[1].split(';', 1)[0]


@staff_member_required
def launch_crawl_report_csv(request):
    response = HttpResponse(content_type='text/csv; charset=utf-8')
    response['Content-Disposition'] = 'attachment; filename="launch-crawl-report.csv"'
    fieldnames = ['url', 'page_type', 'http_status', 'robots_meta', 'status', 'notes']
    writer = csv.DictWriter(response, fieldnames=fieldnames)
    writer.writeheader()
    for row in IndexingMonitorURL.objects.order_by('page_type', 'url'):
        status = 'fail' if row.index_status == IndexingMonitorURL.IndexStatus.ERROR or row.has_launch_risk else 'pass'
        writer.writerow({'url': row.url, 'page_type': row.page_type, 'http_status': row.http_status, 'robots_meta': _robots_from_notes(row.notes), 'status': status, 'notes': row.notes})
    return response


